namespace RossWright;

/// <summary>
/// Contains methods that return plausible random values for things like
/// names, addresses, emails, companies, dates, prices, coordinates, lorem ipsum, and more 
/// for populating test databases, seeding demo data, and exercising UI layouts
/// </summary>
public static class Populi
{
    static System.Random r = new System.Random();
    /// <summary>Returns a random <see cref="bool"/>.</summary>
    /// <param name="pctBiasToTrue">Percentage likelihood of returning <c>true</c> (0–100). Defaults to 50.</param>
    public static bool NextBool(int pctBiasToTrue = 50) => r.Next(0, 99) < pctBiasToTrue;
    /// <summary>Returns a random non-negative integer less than <paramref name="max"/>.</summary>
    /// <param name="max">Exclusive upper bound. Defaults to <see cref="int.MaxValue"/>.</param>
    public static int NextInt(int max = int.MaxValue) => r.Next(max);
    /// <summary>Returns a random integer within [<paramref name="min"/>, <paramref name="max"/>).</summary>
    /// <param name="min">Inclusive lower bound.</param>
    /// <param name="max">Exclusive upper bound.</param>
    public static int NextInt(int min, int max) => r.Next(min, max);
    /// <summary>Returns a random non-negative double less than <paramref name="max"/>.</summary>
    /// <param name="max">Exclusive upper bound. Defaults to <see cref="double.MaxValue"/>.</param>
    public static double NextDouble(double max = double.MaxValue) => r.NextDouble() * max;
    /// <summary>Returns a random double within [<paramref name="min"/>, <paramref name="max"/>).</summary>
    /// <param name="min">Inclusive lower bound.</param>
    /// <param name="max">Exclusive upper bound.</param>
    public static double NextDouble(double min, double max) => NextDouble(max - min) + min;
    /// <summary>Returns a random price (two decimal places) between 0 and <paramref name="max"/>.</summary>
    /// <param name="max">Exclusive upper bound. Defaults to <see cref="double.MaxValue"/>.</param>
    public static double NextPrice(double max = double.MaxValue) => NextPrice(0, max);
    /// <summary>Returns a random price (two decimal places) within [<paramref name="min"/>, <paramref name="max"/>).</summary>
    /// <param name="min">Inclusive lower bound.</param>
    /// <param name="max">Exclusive upper bound.</param>
    public static double NextPrice(double min, double max) => Math.Floor(NextDouble(max - min) + min * 100) / 100;
    /// <summary>Returns a random ASCII letter (A–Z or a–z).</summary>
    public static string NextLetter() => ((char)(OneOf(r.Next('A', 'Z' + 1), r.Next('a', 'z' + 1)))).ToString();
    /// <summary>Returns a random value from an <see langword="enum"/> type <typeparamref name="T"/>.</summary>
    /// <typeparam name="T">An enum type.</typeparam>
    public static T Next<T>()
    {
        var values = Enum.GetValues(typeof(T));
        return (T)values.GetValue(r.Next(values.Length))!;
    }
    /// <summary>Returns a random element from <paramref name="choices"/>.</summary>
    /// <param name="choices">The sequence to pick from.</param>
    public static T OneOf<T>(IEnumerable<T> choices) => choices.Skip(r.Next(choices.Count())).First();
    /// <summary>Returns a random element from the provided <paramref name="choices"/>.</summary>
    /// <param name="choices">One or more values to pick from.</param>
    public static T OneOf<T>(params T[] choices) => choices[r.Next(choices.Length)];
    /// <summary>Returns a random element from <paramref name="weightedChoices"/>, where each tuple pairs a value with its relative weight.</summary>
    /// <param name="weightedChoices">Tuples of (value, weight). Higher weights increase selection probability.</param>
    public static T OneOf<T>(params (T, int)[] weightedChoices)
    {
        var sumofWeights = weightedChoices.Sum(_ => Math.Max(0, _.Item2));
        var pick = r.Next(sumofWeights);
        int i = 0;
        while (pick >= 0) pick -= Math.Max(0, weightedChoices[i++].Item2);
        return weightedChoices[i - 1].Item1;
    }

    /// <summary>Returns a randomly chosen subset of exactly <paramref name="count"/> elements from <paramref name="choices"/>.</summary>
    /// <param name="count">Number of elements to select.</param>
    /// <param name="choices">The pool to select from. If smaller than <paramref name="count"/>, all elements are returned.</param>
    public static T[] SomeOf<T>(int count, params T[] choices)
    {
        if (choices.Length < count) return choices;
        List<T> picks = new List<T>(choices);
        for (int x = 0; x < choices.Length - count; x++)
            picks.RemoveAt(NextInt(picks.Count));
        return picks.ToArray();
    }

    /// <summary>Returns a random element from an <see cref="ICollection{T}"/>.</summary>
    /// <param name="choices">The collection to pick from.</param>
    public static T OutOf<T>(ICollection<T> choices) => choices.ElementAt(r.Next(choices.Count));
    /// <summary>Returns a random element from an <see cref="IList{T}"/>.</summary>
    /// <param name="choices">The list to pick from.</param>
    public static T OutOf<T>(IList<T> choices) => choices[r.Next(choices.Count)];
    /// <summary>Returns a random element from an array.</summary>
    /// <param name="choices">The array to pick from.</param>
    public static T OutOf<T>(T[] choices) => choices[r.Next(choices.Length)];


    /// <summary>Returns a random full name (first + last).</summary>
    public static string NextName() => $"{NextFirstName()} {NextSurname()}";
    /// <summary>Returns a random first name (male or female).</summary>
    public static string NextFirstName() => OneOf(OneOf(maleNames), OneOf(femaleNames));
    /// <summary>Returns a random surname.</summary>
    public static string NextSurname() => OneOf(surnames);
    /// <summary>Returns a random US place name (city or geographic name).</summary>
    public static string NextPlace() => OneOf(places);
    /// <summary>Returns a random US state full name (e.g., "California").</summary>
    public static string NextFullState() => OneOf(fullStateNames);
    /// <summary>Returns a random US state abbreviation (e.g., "CA").</summary>
    public static string NextShortState() => OneOf(shortStateAbbrs);
    /// <summary>Returns a random US-style street address (e.g., "4821 Springfield Ave").</summary>
    public static string NextAddress() => $"{NextNumberNoLeadZero(r.Next(3, 6))} {OneOf(NextPlace(), NextSurname())} {OneOf(streetTypes)}";
    /// <summary>Returns a random email address derived from a full name string.</summary>
    /// <param name="name">Full name used to build the local part (spaces replaced with dots). Falls back to <see cref="NextName"/> if <see langword="null"/>.</param>
    public static string NextEmail(string name) => $"{(name ?? NextName()).Replace(' ', '.')}@{OneOf(domains)}";
    /// <summary>Returns a random email address in the form <c>firstName.surname@domain</c>.</summary>
    /// <param name="firstName">The first name portion of the local part.</param>
    /// <param name="surname">The surname portion of the local part.</param>
    public static string NextEmail(string firstName, string surname) => $"{firstName}.{surname}@{OneOf(domains)}";
    /// <summary>Returns a random fictitious company name (e.g., "Henderson Corp").</summary>
    public static string NextCompany() => $"{OneOf(NextFullState(), NextSurname(), NextPlace())} {OneOf("Co", "Company", "Corp", "Inc", "Incorporated", "Group Holdings", "LLC")}";

    /// <summary>Returns a random numeric string of <paramref name="digits"/> digits with no leading zero.</summary>
    /// <param name="digits">Total number of digits.</param>
    public static string NextNumberNoLeadZero(int digits) => string.Concat(r.Next(1, 10).ToString(), NextNumber(digits - 1));
    /// <summary>Returns a random numeric string of exactly <paramref name="digits"/> digits (may include leading zeros).</summary>
    /// <param name="digits">Number of digits to generate.</param>
    public static string NextNumber(int digits) => string.Concat(Enumerable.Range(0, digits).Select(_ => r.Next(10).ToString()).ToArray());
    /// <summary>Returns a formatted numeric string with digit groups joined by <paramref name="separator"/> (e.g., a phone number or SSN).</summary>
    /// <param name="separator">String placed between each digit group.</param>
    /// <param name="digitGroups">Sizes of each digit group. Defaults to a single 9-digit group if empty.</param>
    public static string NextNumber(string separator, params int[] digitGroups) => string.Join(separator, (digitGroups.Length == 0 ? new int[] { 9 } : digitGroups).Select(NextNumber));

    /// <summary>Converts a name into a plausible website URL (e.g., "Acme Corp" → "http://www.AcmeCorp.com").</summary>
    /// <param name="name">The name to convert; spaces are removed.</param>
    public static string AsWebsite(string name) => $"http://www.{string.Concat(name.Split(new char[] { ' ' }, StringSplitOptions.RemoveEmptyEntries))}.{OneOf("com", "net", "us", "biz", "org")}";

    /// <summary>Returns a random latitude within the contiguous United States (~24.7° to ~49.3°).</summary>
    public static double NextUsLat() => NextDouble(24.7433195, 49.3457868);
    /// <summary>Returns a random longitude within the contiguous United States (~-124.8° to ~-67.0°).</summary>
    public static double NextUsLong() => NextDouble(-124.7844079, -66.9513812);

    /// <summary>Returns a random future date within <paramref name="maxDays"/> days from today.</summary>
    /// <param name="maxDays">Maximum number of days into the future. Defaults to 1826 (~5 years).</param>
    public static DateTime NextFutureDate(int maxDays = 1826) =>
        DateTime.Today.AddDays(r.Next(maxDays));
    /// <summary>Returns a random past date within <paramref name="maxDays"/> days before today.</summary>
    /// <param name="maxDays">Maximum number of days into the past.</param>
    public static DateTime NextPastDate(int maxDays) =>
        DateTime.Today.AddDays(-r.Next(maxDays));

    /// <summary>Returns a random past date between <paramref name="minDays"/> and <paramref name="maxDays"/> days before today.</summary>
    /// <param name="minDays">Minimum number of days into the past. Defaults to 1.</param>
    /// <param name="maxDays">Maximum number of days into the past. Defaults to 1826 (~5 years).</param>
    public static DateTime NextPastDate(int minDays = 1, int maxDays = 1826) =>
        DateTime.Today.AddDays(-r.Next(minDays, maxDays));
    /// <summary>Returns a random past date no earlier than <paramref name="after"/>.</summary>
    /// <param name="after">The earliest allowable date.</param>
    public static DateTime NextPastDateAfter(DateTime after) =>
        NextPastDate((int)(DateTime.UtcNow - after).TotalDays);

    /// <summary>Returns a random birthdate for a person of approximately <paramref name="age"/> years old.</summary>
    /// <param name="age">Approximate age in years. Defaults to 22.</param>
    public static DateTime NextBirthdate(int age = 22) => DateTime.Today.AddYears(-age - 1).AddDays(r.Next(365));

    /// <summary>Returns a Lorem Ipsum placeholder string of <paramref name="words"/> words.</summary>
    /// <param name="words">Number of words to include. Defaults to 69.</param>
    public static string LoremIpsum(int words = 69) =>
        string.Join(" ", Enumerable.Range(0, words).Select(i => loremIpsum[i % loremIpsum.Length]));

    /// <summary>Returns a single random common English word.</summary>
    public static string NextWord() => OneOf(words);
    /// <summary>Returns <paramref name="count"/> random common English words joined by spaces.</summary>
    /// <param name="count">Number of words to return.</param>
    public static string NextWords(int count) =>
        string.Join(' ', Enumerable.Range(0, count).Select(_ => OneOf(words)));


